// frontend/src/components/jobs/JobList.jsx
import React from 'react';
import JobCard from './JobCard';

const JobList = ({ jobs, variant, onSelectJob }) => {
    const containerStyle = {
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: '24px',
        width: '100%'
    };

    const safeJobs = Array.isArray(jobs) ? jobs : [];

    return (
        <div style={containerStyle}>
            {safeJobs.map((job) => {
                // Menentukan ID yang valid (prioritas id, cadangan id_lowongan)
                const uniqueKey = job.id || job.id_lowongan;

                return (
                    <div key={uniqueKey}> 
                        <JobCard 
                            job={{ ...job, id: uniqueKey }} // Pastikan objek job punya id
                            isFull={variant === 'full'} 
                            onClick={() => onSelectJob && onSelectJob(job)}
                        />
                    </div>
                );
            })}
        </div>
    );
};

export default JobList;
